const gridItem = (name, path) => {
  const isMobile = window.innerWidth <= 600; // Define the breakpoint for mobile screens

  return (
    <Container
      sx={{
        width: { sm: '15rem', xs: '7rem' },
        height: { sm: '8rem', xs: '3rem' },
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        bgcolor: '#292929',
        m: 'auto',
        p: 1,
        borderRadius: '10px',
        transition: '0.5s',
        '&:hover': { transform: 'scale(1.05)' }
      }}
    >
      <Box component="img" src={path} alt={`${name} logo`} height="45%" mr={2} />
      <Typography color="#e1e1e1">{isMobile ? 'JS' : name}</Typography>
    </Container>
  );
};

function Skills () {
    return (
        <Container 
          maxWidth='none'
          id='Skills'
          sx={{
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center',
            width: '75%',
            mx: 'auto',
            mb: {xs: '10vh', sm: '25vh'}, 
            // mb: '25vh'
          }}
        >
          <Typography 
            id='skills'
            variant='h2'
            my={4} 
          >
            Skills
          </Typography>
          <Box sx={{ display: 'flex', justifyContent: 'center' }}>
            <Grid container spacing={4}>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('Python', python_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('Flask', flask_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('NumPy', numpy_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('Pandas', pandas_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('JavaScript', javascript_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('NodeJS', node_img)}
              </Grid>              
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('React', react_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('Material UI', mui_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('HTML5', html_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('CSS3', css_img)}
              </Grid>
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('GitHub', github_img)}
              </Grid>    
              <Grid item xs={12} sm={6} md={4} lg={3}>
                {gridItem('Render', render_img)}
              </Grid>                            
            </Grid>
          </Box>
      </Container>
    );
}

export default Skills;
